import type { LogEntry, ResolvedExercise } from '../types';
import { MAX_WEIGHT, MIN_WEIGHT, parseReps } from '../logic/progression';
import { parseSeconds } from '../logic/timer';
import { Timer } from './Timer';

interface Props {
  exercise: ResolvedExercise;
  index: number;
  globalDay: number;
  entry: LogEntry | undefined;
  suggestedWeight: number | null;
  lastWeight: number | null;
  // List of weights the user is allowed to pick for this exercise. null when
  // the exercise has no weight, or when the user hasn't configured inventory
  // yet (free-input fallback).
  allowedWeights?: number[] | null;
  inventoryConfigured?: boolean;
  onLog: (key: string, partial: Partial<LogEntry>, options?: { remove?: boolean }) => void;
  onPlayVideo: (videoId: string, start?: number) => void;
}

export function ExerciseCard({
  exercise,
  index,
  globalDay,
  entry,
  suggestedWeight,
  lastWeight,
  allowedWeights = null,
  inventoryConfigured = false,
  onLog,
  onPlayVideo,
}: Props) {
  const key = `${globalDay}_${index}`;
  const completed = entry?.completed ?? false;
  const difficulty = entry?.difficulty;
  const notes = entry?.notes ?? '';
  const weight = entry?.weight;
  const increment = exercise.weightIncrement ?? 5;
  const maxSets = exercise.sets;
  const maxReps = parseReps(exercise.reps);
  const failedSet = entry?.failedSet ?? 1;
  const failedRep = entry?.failedRep ?? 1;
  const repSeconds = parseSeconds(exercise.reps);
  const restSeconds = parseSeconds(exercise.rest);

  function setWeight(next: number | null) {
    if (next == null || Number.isNaN(next)) {
      onLog(key, { weight: undefined }, { remove: !difficulty && !notes });
      return;
    }
    const clamped = Math.max(MIN_WEIGHT, Math.min(MAX_WEIGHT, next));
    onLog(key, {
      exercise: exercise.name,
      weight: clamped,
      day: globalDay,
      timestamp: Date.now(),
    });
  }

  function handleWeightInput(e: Event) {
    const value = (e.target as HTMLInputElement).value;
    if (value === '') {
      setWeight(null);
      return;
    }
    const parsed = parseFloat(value);
    if (Number.isFinite(parsed)) setWeight(parsed);
  }

  function setDifficulty(d: LogEntry['difficulty']) {
    onLog(key, {
      exercise: exercise.name,
      difficulty: d,
      day: globalDay,
      timestamp: Date.now(),
      ...(d !== 'failed' ? { failedSet: undefined, failedRep: undefined } : {}),
    });
  }

  function setNotes(value: string) {
    const trimmed = value.trim();
    onLog(
      key,
      {
        exercise: exercise.name,
        notes: trimmed || undefined,
        day: globalDay,
        timestamp: Date.now(),
      },
      { remove: !trimmed && !weight && !difficulty && !completed },
    );
  }

  function toggleDone() {
    if (completed) {
      onLog(
        key,
        { completed: undefined },
        { remove: !weight && !difficulty && !notes },
      );
    } else {
      onLog(key, {
        exercise: exercise.name,
        completed: true,
        day: globalDay,
        timestamp: Date.now(),
      });
    }
  }

  const placeholder = suggestedWeight != null ? String(suggestedWeight) : lastWeight != null ? String(lastWeight) : '—';

  const useChipPicker =
    inventoryConfigured && Array.isArray(allowedWeights) && allowedWeights.length > 0;
  const inventoryEmptyForExercise =
    inventoryConfigured && Array.isArray(allowedWeights) && allowedWeights.length === 0;
  const chipWeights: number[] = useChipPicker ? [...(allowedWeights as number[])] : [];
  const weightIsDrift =
    useChipPicker &&
    typeof weight === 'number' &&
    !chipWeights.includes(weight);
  if (weightIsDrift) {
    chipWeights.push(weight as number);
    chipWeights.sort((a, b) => a - b);
  }

  function stepWeight(direction: 1 | -1) {
    if (useChipPicker) {
      const opts = allowedWeights as number[];
      const current = typeof weight === 'number' ? weight : suggestedWeight ?? opts[0];
      const inList = opts.indexOf(current);
      if (inList >= 0) {
        const next = opts[Math.max(0, Math.min(opts.length - 1, inList + direction))];
        setWeight(next);
        return;
      }
      // Drift case: snap to nearest owned weight in the chosen direction.
      if (direction === 1) {
        const next = opts.find((w) => w > current);
        setWeight(next ?? opts[opts.length - 1]);
      } else {
        const next = [...opts].reverse().find((w) => w < current);
        setWeight(next ?? opts[0]);
      }
      return;
    }
    const current = weight ?? suggestedWeight ?? MIN_WEIGHT;
    setWeight(current + direction * increment);
  }

  return (
    <article
      class={
        'rounded-[2rem] p-6 transition-all ' +
        (completed
          ? 'bg-flux-accent/15 shadow-flux-card'
          : 'bg-flux-card shadow-flux-card')
      }
      data-exercise-index={index}
      data-completed={completed ? 'true' : 'false'}
    >
      <header class="flex items-start justify-between gap-3">
        <div class="flex-1">
          <h3 class="text-lg font-medium leading-tight text-flux-text-primary">
            {exercise.name}
          </h3>
          {exercise.unmapped && (
            <span
              class="mt-1 inline-block rounded-full bg-flux-soft px-2.5 py-0.5 text-[10px] uppercase tracking-[0.15em] text-flux-text-tertiary"
              data-testid={`unmapped-${index}`}
              title="Imported from a legacy export. No demo or technique notes available."
            >
              Unmapped
            </span>
          )}
        </div>
        {exercise.demoVideoId ? (
          <button
            type="button"
            class="shrink-0 rounded-full bg-flux-soft px-3 py-1.5 text-[10px] font-medium uppercase tracking-[0.15em] text-flux-text-secondary transition-colors hover:text-flux-text-primary"
            onClick={() => onPlayVideo(exercise.demoVideoId!, exercise.demoVideoStart)}
            data-testid={`video-${index}`}
          >
            Video
          </button>
        ) : (
          <span class="shrink-0 rounded-full bg-flux-soft px-3 py-1.5 text-[10px] uppercase tracking-[0.15em] text-flux-text-tertiary">
            No video
          </span>
        )}
      </header>

      <dl class="mt-4 grid grid-cols-3 gap-2 rounded-2xl bg-flux-soft px-4 py-3">
        <div class="flex flex-col items-center">
          <dt class="text-[9px] font-medium uppercase tracking-[0.18em] text-flux-text-tertiary">Sets</dt>
          <dd class="mt-0.5 text-base font-medium text-flux-text-primary">{exercise.sets}</dd>
        </div>
        <div class="flex flex-col items-center border-x border-flux-border">
          <dt class="text-[9px] font-medium uppercase tracking-[0.18em] text-flux-text-tertiary">Reps</dt>
          <dd class="mt-0.5 text-base font-medium text-flux-text-primary">{exercise.reps}</dd>
        </div>
        <div class="flex flex-col items-center">
          <dt class="text-[9px] font-medium uppercase tracking-[0.18em] text-flux-text-tertiary">Rest</dt>
          <dd class="mt-0.5 text-base font-medium text-flux-text-primary">{exercise.rest}</dd>
        </div>
      </dl>

      {exercise.techniqueNote && (
        <p class="mt-3 text-xs leading-snug text-flux-text-tertiary">{exercise.techniqueNote}</p>
      )}

      {(repSeconds || restSeconds) && (
        <div class="mt-4 flex flex-wrap gap-2">
          {repSeconds && (
            <Timer label="Exercise" seconds={repSeconds} testId={`timer-ex-${index}`} />
          )}
          {restSeconds && (
            <Timer label="Rest" seconds={restSeconds} testId={`timer-rest-${index}`} />
          )}
        </div>
      )}

      {exercise.usesWeight && !inventoryEmptyForExercise && (
        <div class="mt-4 flex flex-wrap items-center gap-2">
          <span class="text-[10px] font-medium uppercase tracking-[0.18em] text-flux-text-tertiary">
            Weight
          </span>
          <button
            type="button"
            class="flex h-8 w-8 items-center justify-center rounded-full bg-flux-soft text-base text-flux-text-secondary transition-colors hover:text-flux-text-primary"
            onClick={() => stepWeight(-1)}
            aria-label="Decrease weight"
          >
            −
          </button>
          {useChipPicker ? (
            <div
              class="flex flex-1 flex-nowrap items-center gap-1.5 overflow-x-auto"
              data-testid={`weight-chips-${index}`}
            >
              {chipWeights.map((w) => {
                const selected = weight === w;
                const drift = !allowedWeights!.includes(w);
                return (
                  <button
                    key={w}
                    type="button"
                    aria-pressed={selected}
                    onClick={() => setWeight(w)}
                    data-testid={`weight-chip-${index}-${w}`}
                    data-drift={drift ? 'true' : 'false'}
                    title={drift ? 'Not in your inventory' : undefined}
                    class={
                      'shrink-0 rounded-full px-3 py-1 text-[11px] font-medium uppercase tracking-[0.15em] transition-colors ' +
                      (selected
                        ? drift
                          ? 'border border-flux-border bg-transparent text-flux-text-primary'
                          : 'bg-flux-accent text-flux-accent-fg shadow-flux-soft'
                        : drift
                          ? 'border border-flux-border bg-transparent text-flux-text-tertiary'
                          : 'bg-flux-soft text-flux-text-secondary hover:text-flux-text-primary')
                    }
                  >
                    {w}
                    {drift && (
                      <span
                        class="ml-1 inline-block rounded-full bg-flux-soft px-1.5 py-0.5 text-[9px] tracking-[0.12em] text-flux-text-tertiary"
                        data-testid={`weight-chip-drift-${index}-${w}`}
                      >
                        Unmapped
                      </span>
                    )}
                  </button>
                );
              })}
            </div>
          ) : (
            <input
              type="number"
              class="w-20 rounded-xl bg-flux-soft px-3 py-1.5 text-center text-sm font-medium tabular-nums text-flux-text-primary placeholder:text-flux-text-tertiary"
              value={weight ?? ''}
              placeholder={placeholder}
              onInput={handleWeightInput}
              data-testid={`weight-${index}`}
            />
          )}
          <button
            type="button"
            class="flex h-8 w-8 items-center justify-center rounded-full bg-flux-soft text-base text-flux-text-secondary transition-colors hover:text-flux-text-primary"
            onClick={() => stepWeight(1)}
            aria-label="Increase weight"
          >
            +
          </button>
          <span class="text-[10px] font-medium uppercase tracking-[0.18em] text-flux-text-tertiary">
            lbs
          </span>
          {suggestedWeight != null && (
            <span class="ml-auto text-[10px] uppercase tracking-[0.15em] text-flux-text-tertiary">
              ~{suggestedWeight}
            </span>
          )}
        </div>
      )}

      <div class="mt-5">
        <button
          type="button"
          class={
            'w-full rounded-2xl px-4 py-3 text-xs font-medium uppercase tracking-[0.2em] transition-all ' +
            (completed
              ? 'bg-flux-accent text-flux-accent-fg shadow-flux-soft'
              : 'bg-flux-soft text-flux-text-secondary hover:text-flux-text-primary')
          }
          onClick={toggleDone}
          data-testid={`done-${index}`}
        >
          {completed ? '✓ Done' : 'Mark Done'}
        </button>

        {completed && (
          <>
            <div class="mt-4 grid grid-cols-4 gap-1.5">
              {(['failed', 'easy', 'good', 'hard'] as const).map((d) => {
                const selected = difficulty === d || (!difficulty && d === 'good');
                return (
                  <button
                    key={d}
                    type="button"
                    aria-pressed={selected}
                    class={
                      'rounded-full px-2 py-2 text-[10px] font-medium uppercase tracking-[0.15em] transition-colors ' +
                      (selected
                        ? 'bg-flux-accent text-flux-accent-fg'
                        : 'bg-flux-soft text-flux-text-secondary hover:text-flux-text-primary')
                    }
                    onClick={() => setDifficulty(d)}
                    data-testid={`difficulty-${index}-${d}`}
                  >
                    {d.toUpperCase()}
                  </button>
                );
              })}
            </div>

            {difficulty === 'failed' && (
              <div class="mt-4 space-y-3 rounded-2xl bg-flux-soft p-4">
                <label class="block text-[10px] font-medium uppercase tracking-[0.18em] text-flux-text-tertiary">
                  Failed on set: <span class="text-flux-text-primary">{failedSet}</span> / {maxSets}
                  <input
                    type="range"
                    min={1}
                    max={maxSets}
                    value={failedSet}
                    class="mt-2 block w-full accent-flux-accent"
                    onChange={(e) =>
                      onLog(key, {
                        exercise: exercise.name,
                        failedSet: Number((e.target as HTMLInputElement).value),
                        day: globalDay,
                        timestamp: Date.now(),
                      })
                    }
                  />
                </label>
                <label class="block text-[10px] font-medium uppercase tracking-[0.18em] text-flux-text-tertiary">
                  Failed on rep: <span class="text-flux-text-primary">{failedRep}</span> / {maxReps}
                  <input
                    type="range"
                    min={1}
                    max={maxReps}
                    value={failedRep}
                    class="mt-2 block w-full accent-flux-accent"
                    onChange={(e) =>
                      onLog(key, {
                        exercise: exercise.name,
                        failedRep: Number((e.target as HTMLInputElement).value),
                        day: globalDay,
                        timestamp: Date.now(),
                      })
                    }
                  />
                </label>
              </div>
            )}

            <textarea
              class="mt-4 block w-full rounded-2xl bg-flux-soft px-4 py-3 text-xs text-flux-text-primary placeholder:text-flux-text-tertiary"
              rows={2}
              placeholder="Notes (optional)"
              value={notes}
              onChange={(e) => setNotes((e.target as HTMLTextAreaElement).value)}
              data-testid={`notes-${index}`}
            />
          </>
        )}
      </div>
    </article>
  );
}

import { openDb, dbGet, dbPut, dbPutMany, dbDelete, dbClear, dbGetAll } from '../../db/idb';
import { EQUIPMENT_CATALOG, type EquipmentKind } from '../../data/equipmentCatalog';
import {
  cloneDefaultLocationsState,
  type Inventory,
  type InventoryItem,
  type Location,
  type LocationsState,
} from '../../data/inventory';
import type { LogEntry, LogMap, Program, WorkoutState } from './types';

const DB_NAME = 'flux-db';
// Bumped to 3 to add the 'inventory' store. New users get it on first open;
// existing users get an automatic onupgradeneeded migration via openDb.
const DB_VERSION = 3;
const STATE_STORE = 'state';
const LOG_STORE = 'log';
const PROGRAM_STORE = 'program';
const INVENTORY_STORE = 'inventory';
const STATE_KEY = 'current';
const PROGRAM_KEY = 'current';
const INVENTORY_KEY = 'current';

const DIFFICULTIES = new Set(['easy', 'good', 'hard', 'failed']);

let dbPromise: Promise<IDBDatabase> | null = null;

export function getDb(): Promise<IDBDatabase> {
  if (!dbPromise) {
    dbPromise = openDb({
      name: DB_NAME,
      version: DB_VERSION,
      stores: [
        { name: STATE_STORE },
        { name: LOG_STORE },
        { name: PROGRAM_STORE },
        { name: INVENTORY_STORE },
      ],
    });
  }
  return dbPromise;
}

export const DEFAULT_STATE: WorkoutState = { globalDay: 1, currentPhase: 'p1' };

export async function loadState(): Promise<WorkoutState> {
  const db = await getDb();
  const saved = await dbGet<WorkoutState>(db, STATE_STORE, STATE_KEY);
  if (!saved) return { ...DEFAULT_STATE };
  const day = Number(saved.globalDay);
  return {
    globalDay: Number.isInteger(day) && day >= 1 ? day : 1,
    currentPhase:
      typeof saved.currentPhase === 'string' ? saved.currentPhase : 'p1',
  };
}

export async function saveState(state: WorkoutState): Promise<void> {
  const db = await getDb();
  await dbPut(db, STATE_STORE, state, STATE_KEY);
}

export async function loadLog(): Promise<LogMap> {
  const db = await getDb();
  const tx = db.transaction(LOG_STORE, 'readonly');
  const store = tx.objectStore(LOG_STORE);
  return new Promise((resolve, reject) => {
    const result: LogMap = {};
    const req = store.openCursor();
    req.onsuccess = () => {
      const cursor = req.result;
      if (cursor) {
        result[String(cursor.key)] = cursor.value as LogEntry;
        cursor.continue();
      } else {
        resolve(result);
      }
    };
    req.onerror = () => reject(req.error);
  });
}

export async function putLogEntry(key: string, entry: LogEntry): Promise<void> {
  const db = await getDb();
  await dbPut(db, LOG_STORE, entry, key);
}

export async function putLogEntries(
  entries: Array<{ key: string; entry: LogEntry }>,
): Promise<void> {
  const db = await getDb();
  await dbPutMany(
    db,
    LOG_STORE,
    entries.map(({ key, entry }) => ({ key, value: entry })),
  );
}

export async function deleteLogEntry(key: string): Promise<void> {
  const db = await getDb();
  await dbDelete(db, LOG_STORE, key);
}

export async function clearAll(): Promise<void> {
  const db = await getDb();
  await dbClear(db, STATE_STORE);
  await dbClear(db, LOG_STORE);
  await dbClear(db, PROGRAM_STORE);
  await dbClear(db, INVENTORY_STORE);
}

export async function loadProgram(): Promise<Program | null> {
  const db = await getDb();
  const saved = await dbGet<Program>(db, PROGRAM_STORE, PROGRAM_KEY);
  return saved ?? null;
}

export async function saveProgram(program: Program): Promise<void> {
  const db = await getDb();
  await dbPut(db, PROGRAM_STORE, program, PROGRAM_KEY);
}

export async function clearProgram(): Promise<void> {
  const db = await getDb();
  await dbDelete(db, PROGRAM_STORE, PROGRAM_KEY);
}

export async function loadLocations(): Promise<LocationsState> {
  const db = await getDb();
  const saved = await dbGet<unknown>(db, INVENTORY_STORE, INVENTORY_KEY);
  if (!saved) return cloneDefaultLocationsState();
  return sanitizeLocationsState(saved);
}

export async function saveLocations(state: LocationsState): Promise<void> {
  const db = await getDb();
  await dbPut(db, INVENTORY_STORE, state, INVENTORY_KEY);
}

// Returns the parsed list of all log entries in insertion order. Useful for
// debugging and for future analytics; the working interface is loadLog().
export async function listLogValues(): Promise<LogEntry[]> {
  const db = await getDb();
  return dbGetAll<LogEntry>(db, LOG_STORE);
}

export function sanitizeLogEntry(raw: unknown): Partial<LogEntry> | null {
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
  const entry = raw as Record<string, unknown>;
  const out: Partial<LogEntry> = {};

  if (typeof entry.exercise === 'string') {
    out.exercise = entry.exercise.slice(0, 200);
  }
  if (typeof entry.weight === 'number' && Number.isFinite(entry.weight)) {
    out.weight = entry.weight;
  } else if (typeof entry.weight === 'string') {
    const parsed = parseFloat(entry.weight);
    if (Number.isFinite(parsed)) out.weight = parsed;
  }
  if (typeof entry.difficulty === 'string' && DIFFICULTIES.has(entry.difficulty)) {
    out.difficulty = entry.difficulty as LogEntry['difficulty'];
  }
  if (typeof entry.notes === 'string') {
    out.notes = entry.notes.slice(0, 500);
  }
  if (typeof entry.completed === 'boolean') {
    out.completed = entry.completed;
  }
  if (typeof entry.day === 'number' && Number.isFinite(entry.day)) {
    out.day = entry.day;
  }
  if (typeof entry.timestamp === 'number' && Number.isFinite(entry.timestamp)) {
    out.timestamp = entry.timestamp;
  }
  if (typeof entry.failedSet === 'number' && Number.isFinite(entry.failedSet)) {
    out.failedSet = entry.failedSet;
  }
  if (typeof entry.failedRep === 'number' && Number.isFinite(entry.failedRep)) {
    out.failedRep = entry.failedRep;
  }
  return out;
}

function isObject(v: unknown): v is Record<string, unknown> {
  return typeof v === 'object' && v !== null && !Array.isArray(v);
}

function sanitizeWeights(raw: unknown): number[] {
  if (!Array.isArray(raw)) return [];
  const seen = new Set<number>();
  for (const v of raw) {
    const n = typeof v === 'number' ? v : typeof v === 'string' ? parseFloat(v) : NaN;
    if (Number.isFinite(n) && n > 0) seen.add(n);
  }
  return Array.from(seen).sort((a, b) => a - b);
}

export function sanitizeInventoryItem(
  kind: EquipmentKind,
  raw: unknown,
): InventoryItem | null {
  if (!isObject(raw)) return null;
  const item: InventoryItem = {
    kind,
    ownedWeights: sanitizeWeights(raw.ownedWeights),
  };
  if (typeof raw.note === 'string' && raw.note.trim().length > 0) {
    item.note = raw.note.slice(0, 200);
  }
  return item;
}

export function sanitizeInventory(raw: unknown): Inventory {
  if (!isObject(raw)) return {};
  const out: Inventory = {};
  for (const [key, value] of Object.entries(raw)) {
    if (!(key in EQUIPMENT_CATALOG)) continue;
    const kind = key as EquipmentKind;
    const item = sanitizeInventoryItem(kind, value);
    if (item) out[kind] = item;
  }
  return out;
}

function sanitizeLocation(id: string, raw: unknown): Location | null {
  if (!isObject(raw)) return null;
  const name =
    typeof raw.name === 'string' && raw.name.trim().length > 0
      ? raw.name.slice(0, 80)
      : id;
  return {
    id,
    name,
    inventory: sanitizeInventory(raw.inventory),
  };
}

export function sanitizeLocationsState(raw: unknown): LocationsState {
  if (!isObject(raw)) return cloneDefaultLocationsState();
  const locationsRaw = isObject(raw.locations) ? raw.locations : null;
  const locations: Record<string, Location> = {};
  if (locationsRaw) {
    for (const [id, value] of Object.entries(locationsRaw)) {
      const loc = sanitizeLocation(id, value);
      if (loc) locations[id] = loc;
    }
  }
  if (Object.keys(locations).length === 0) {
    locations.default = { id: 'default', name: 'Home', inventory: {} };
  }
  let activeId =
    typeof raw.activeLocationId === 'string' ? raw.activeLocationId : '';
  if (!locations[activeId]) {
    activeId = locations.default ? 'default' : Object.keys(locations)[0];
  }
  return { locations, activeLocationId: activeId };
}

// Reset the cached connection — only used by tests that wipe the DB between runs.
export function _resetDbForTests(): void {
