{"url":"https://api.github.com/repos/gunk-dev/flux/pulls/comments/3326735554","pull_request_review_id":4392628194,"id":3326735554,"node_id":"PRRC_kwDORLHYJ87GSfTC","diff_hunk":"@@ -158,6 +182,81 @@ export function sanitizeLogEntry(raw: unknown): Partial<LogEntry> | null {
   return out;
 }

+function isObject(v: unknown): v is Record<string, unknown> {
+  return typeof v === 'object' && v !== null && !Array.isArray(v);
+}
+
+function sanitizeWeights(raw: unknown): number[] {
+  if (!Array.isArray(raw)) return [];
+  const seen = new Set<number>();
+  for (const v of raw) {
+    const n = typeof v === 'number' ? v : typeof v === 'string' ? parseFloat(v) : NaN;
+    if (Number.isFinite(n) && n > 0) seen.add(n);
+  }
+  return Array.from(seen).sort((a, b) => a - b);
+}
+
+export function sanitizeInventoryItem(
+  kind: EquipmentKind,
+  raw: unknown,
+): InventoryItem | null {
+  if (!isObject(raw)) return null;
+  const item: InventoryItem = {
+    kind,
+    ownedWeights: sanitizeWeights(raw.ownedWeights),
+  };
+  if (typeof raw.note === 'string' && raw.note.trim().length > 0) {
+    item.note = raw.note.slice(0, 200);
+  }
+  return item;
+}
+
+export function sanitizeInventory(raw: unknown): Inventory {
+  if (!isObject(raw)) return {};
+  const out: Inventory = {};
+  for (const [key, value] of Object.entries(raw)) {
+    if (!(key in EQUIPMENT_CATALOG)) continue;","path":"src/tabs/Workouts/state.ts","commit_id":"5a0b546b8afa21b42b5d684ec0971f177c374240","original_commit_id":"5a0b546b8afa21b42b5d684ec0971f177c374240","user":{"login":"patflynn","id":7862557,"node_id":"MDQ6VXNlcjc4NjI1NTc=","avatar_url":"https://avatars.githubusercontent.com/u/7862557?v=4","gravatar_id":"","url":"https://api.github.com/users/patflynn","html_url":"https://github.com/patflynn","followers_url":"https://api.github.com/users/patflynn/followers","following_url":"https://api.github.com/users/patflynn/following{/other_user}","gists_url":"https://api.github.com/users/patflynn/gists{/gist_id}","starred_url":"https://api.github.com/users/patflynn/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/patflynn/subscriptions","organizations_url":"https://api.github.com/users/patflynn/orgs","repos_url":"https://api.github.com/users/patflynn/repos","events_url":"https://api.github.com/users/patflynn/events{/privacy}","received_events_url":"https://api.github.com/users/patflynn/received_events","type":"User","user_view_type":"public","site_admin":false},"body":"Switched to Object.prototype.hasOwnProperty.call(EQUIPMENT_CATALOG, key) so inherited Object.prototype properties (toString, constructor, etc.) cannot smuggle through sanitizeInventory.","created_at":"2026-05-29T20:23:03Z","updated_at":"2026-05-29T20:23:03Z","html_url":"https://github.com/gunk-dev/flux/pull/85#discussion_r3326735554","pull_request_url":"https://api.github.com/repos/gunk-dev/flux/pulls/85","_links":{"self":{"href":"https://api.github.com/repos/gunk-dev/flux/pulls/comments/3326735554"},"html":{"href":"https://github.com/gunk-dev/flux/pull/85#discussion_r3326735554"},"pull_request":{"href":"https://api.github.com/repos/gunk-dev/flux/pulls/85"}},"reactions":{"url":"https://api.github.com/repos/gunk-dev/flux/pulls/comments/3326735554/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket"